<script setup lang="ts">import { reactive, ref } from 'vue'; import { ElMessage, ElMessageBox } from 'element-plus'; import { ApiError, type InstanceItem } from '@ct/shared'; import { dashboard } from '../api'; import AppShell from '../components/AppShell.vue'; import AsyncPanel from '../components/AsyncPanel.vue'; import StatusTag from '../components/StatusTag.vue'; import TokenDialog from '../components/TokenDialog.vue'; import { useAsyncData } from '../composables/useAsyncData'; import { useAutoRefresh } from '../composables/useAutoRefresh'; import { useFiltersStore } from '../stores/filters'; const filters=useFiltersStore();const createOpen=ref(false);const form=reactive({instance_id:'',name:''});const tokenOpen=ref(false);const token=ref('');const grace=ref<string>();const state=useAsyncData(async()=>(await dashboard.instances()).items);function message(e:unknown){if(e instanceof ApiError)return {instance_exists:'实例 ID 已存在',instance_not_found:'实例不存在',instance_disabled:'实例已停用'}[e.code]||e.code;return e instanceof Error?e.message:'操作失败'}function showToken(value:string,g?:string){token.value=value;grace.value=g;tokenOpen.value=true}async function create(){if(!/^[a-z0-9-]{1,64}$/.test(form.instance_id)){ElMessage.error('实例 ID 仅允许小写字母、数字和连字符，最长 64 位');return}try{const result=await dashboard.createInstance({...form});createOpen.value=false;showToken(result.token);form.instance_id='';form.name='';filters.loaded=false;await Promise.all([state.reload(),filters.loadInstances()])}catch(e){ElMessage.error(message(e))}}async function rotate(item:InstanceItem){try{await ElMessageBox.confirm('轮换后旧 Token 仍有 24 小时宽限，是否继续？','轮换 Token',{type:'warning'});const result=await dashboard.rotateInstanceToken(item.instance_id);showToken(result.token,result.grace_until)}catch(e){if((e as string)!=='cancel')ElMessage.error(message(e))}}async function toggle(item:InstanceItem,value:boolean){const warning=value?'确认启用该实例？':'停用后该实例全部 Agent token 立即失效';try{await ElMessageBox.confirm(warning,value?'启用实例':'停用实例',{type:'warning'});await dashboard.updateInstance(item.instance_id,{enabled:value});filters.loaded=false;await Promise.all([state.reload(),filters.loadInstances()])}catch(e){if((e as string)!=='cancel')ElMessage.error(message(e));await state.reload()}}useAutoRefresh(state.reload);</script>
<template><AppShell title="实例管理"><template #tools><el-button type="primary" @click="createOpen=true">创建实例</el-button></template><AsyncPanel :loading="state.loading.value" :error="state.error.value" :empty="!state.data.value?.length" @retry="state.reload"><el-table :data="state.data.value"><el-table-column prop="instance_id" label="实例 ID"/><el-table-column prop="name" label="名称"/><el-table-column label="启用"><template #default="s"><el-switch :model-value="s.row.enabled" @change="toggle(s.row,Boolean($event))"/></template></el-table-column><el-table-column prop="created_at" label="创建时间"><template #default="s">{{new Date(s.row.created_at).toLocaleString()}}</template></el-table-column><el-table-column label="Agent"><template #default="s"><div v-for="agent in s.row.agents" :key="agent.id"><StatusTag :value="agent.online?'online':'offline'"/> {{agent.version}} · 积压 {{agent.backlog_estimate}} · {{new Date(agent.last_seen_at).toLocaleString()}}</div><span v-if="!s.row.agents.length">—</span></template></el-table-column><el-table-column label="操作"><template #default="s"><el-button size="small" @click="rotate(s.row)">轮换 Token</el-button></template></el-table-column></el-table></AsyncPanel><el-dialog v-model="createOpen" title="创建实例" width="480px"><el-form :model="form" label-width="90px"><el-form-item label="实例 ID"><el-input v-model="form.instance_id" placeholder="如 prod-cn-1"/></el-form-item><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item></el-form><template #footer><el-button @click="createOpen=false">取消</el-button><el-button type="primary" @click="create">创建</el-button></template></el-dialog><TokenDialog v-model="tokenOpen" :token="token" :grace-until="grace"/></AppShell></template>
